// Generated by forge proof from tui-worktree-detail-enrichment.md
import { describe, test, expect, beforeEach, beforeAll, afterAll } from 'bun:test';
import {
  getTestDb,
  insertWorktree,
  getWorktree,
  insertSpecEntry,
  insertSpecRun,
  getSpecEntryByPath,
  getSpecRunsByEntry,
  transitionWorktreeStatus,
} from './db.js';
import type { Database } from 'bun:sqlite';
import type { SpecRunRow } from './db.js';
import { setupHermeticGit, teardownHermeticGit } from './test-utils.js';

let db: Database;

beforeAll(() => { setupHermeticGit(); });
afterAll(() => { teardownHermeticGit(); });

beforeEach(() => {
  db = getTestDb();
});

// ── Helpers ──────────────────────────────────────────────────

function makeId(): string {
  return `id-${Date.now()}-${Math.random().toString(16).substring(2, 8)}`;
}

function insertTestWorktree(overrides: Partial<Parameters<typeof insertWorktree>[1]> = {}): string {
  const id = overrides.id ?? makeId();
  insertWorktree(db, {
    id,
    spec_path: overrides.spec_path ?? 'specs/feature.md',
    branch: overrides.branch ?? `forge/${id}`,
    worktree_path: overrides.worktree_path ?? `/tmp/wt-${id}`,
    status: 'created',
    ...overrides,
  });
  return id;
}

function insertTestSpecEntry(specPath: string, workGroupId?: string): string {
  const id = makeId();
  insertSpecEntry(db, {
    id,
    spec: specPath,
    status: 'pending',
    source: 'file',
    work_group_id: workGroupId ?? null,
  });
  return id;
}

function insertTestSpecRun(specEntryId: string, overrides: Partial<{
  status: string;
  cost_usd: number;
  duration_seconds: number;
  num_turns: number;
}> = {}): string {
  const runId = makeId();
  insertSpecRun(db, {
    id: makeId(),
    spec_entry_id: specEntryId,
    run_id: runId,
    timestamp: new Date().toISOString(),
    status: overrides.status ?? 'passed',
    cost_usd: overrides.cost_usd ?? 1.50,
    duration_seconds: overrides.duration_seconds ?? 120,
    num_turns: overrides.num_turns ?? 25,
  });
  return runId;
}

// ── Run history data retrieval ──────────────────────────────

describe('TUI worktree detail: run history data retrieval', () => {
  test('loads run history via getSpecEntryByPath + getSpecRunsByEntry', () => {
    const specPath = 'specs/auth.md';
    const wtId = insertTestWorktree({ spec_path: specPath });
    const entryId = insertTestSpecEntry(specPath);

    insertTestSpecRun(entryId, { status: 'passed', cost_usd: 2.0, duration_seconds: 180, num_turns: 30 });
    insertTestSpecRun(entryId, { status: 'failed', cost_usd: 0.50, duration_seconds: 60, num_turns: 10 });

    // Same retrieval pattern as WorktreeDetail component
    const entry = getSpecEntryByPath(db, specPath);
    expect(entry).not.toBeNull();

    const runs = getSpecRunsByEntry(db, entry!.id);
    expect(runs.length).toBe(2);
  });

  test('runs are ordered by timestamp DESC (most recent first)', () => {
    const specPath = 'specs/ordered.md';
    const entryId = insertTestSpecEntry(specPath);

    // Insert runs with different timestamps
    const oldId = makeId();
    insertSpecRun(db, {
      id: makeId(),
      spec_entry_id: entryId,
      run_id: oldId,
      timestamp: '2026-01-01T00:00:00.000Z',
      status: 'failed',
      cost_usd: 1.0,
      duration_seconds: 60,
    });

    const newId = makeId();
    insertSpecRun(db, {
      id: makeId(),
      spec_entry_id: entryId,
      run_id: newId,
      timestamp: '2026-03-17T00:00:00.000Z',
      status: 'passed',
      cost_usd: 2.0,
      duration_seconds: 120,
    });

    const runs = getSpecRunsByEntry(db, entryId);
    expect(runs.length).toBe(2);
    // Most recent first
    expect(runs[0].timestamp > runs[1].timestamp).toBe(true);
  });

  test('each run includes timestamp, status, cost, duration, and turns', () => {
    const specPath = 'specs/fields.md';
    const entryId = insertTestSpecEntry(specPath);
    insertTestSpecRun(entryId, { status: 'passed', cost_usd: 3.25, duration_seconds: 240, num_turns: 42 });

    const runs = getSpecRunsByEntry(db, entryId);
    const run = runs[0];

    expect(run.timestamp).toBeTruthy();
    expect(run.status).toBe('passed');
    expect(run.cost_usd).toBe(3.25);
    expect(run.duration_seconds).toBe(240);
    expect(run.num_turns).toBe(42);
  });
});

// ── Aggregated totals ───────────────────────────────────────

describe('TUI worktree detail: aggregated totals', () => {
  test('computes total cost from all runs', () => {
    const specPath = 'specs/cost-total.md';
    const entryId = insertTestSpecEntry(specPath);

    insertTestSpecRun(entryId, { cost_usd: 2.00 });
    insertTestSpecRun(entryId, { cost_usd: 1.50 });
    insertTestSpecRun(entryId, { cost_usd: 0.75 });

    const runs = getSpecRunsByEntry(db, entryId);

    let totalCost = 0;
    for (const run of runs) {
      totalCost += run.cost_usd ?? 0;
    }

    expect(totalCost).toBe(4.25);
  });

  test('computes total duration from all runs', () => {
    const specPath = 'specs/duration-total.md';
    const entryId = insertTestSpecEntry(specPath);

    insertTestSpecRun(entryId, { duration_seconds: 60 });
    insertTestSpecRun(entryId, { duration_seconds: 120 });

    const runs = getSpecRunsByEntry(db, entryId);

    let totalDuration = 0;
    for (const run of runs) {
      totalDuration += run.duration_seconds ?? 0;
    }

    expect(totalDuration).toBe(180);
  });

  test('handles null cost and duration gracefully', () => {
    const specPath = 'specs/nulls.md';
    const entryId = insertTestSpecEntry(specPath);

    // Insert a run with nulls
    insertSpecRun(db, {
      id: makeId(),
      spec_entry_id: entryId,
      run_id: makeId(),
      timestamp: new Date().toISOString(),
      status: 'failed',
      // cost_usd and duration_seconds default to null
    });

    const runs = getSpecRunsByEntry(db, entryId);
    const run = runs[0];

    let totalCost = 0;
    totalCost += run.cost_usd ?? 0;
    expect(totalCost).toBe(0);

    let totalDuration = 0;
    totalDuration += run.duration_seconds ?? 0;
    expect(totalDuration).toBe(0);
  });
});

// ── Graceful degradation ────────────────────────────────────

describe('TUI worktree detail: graceful degradation', () => {
  test('returns null spec entry for unregistered spec path', () => {
    const entry = getSpecEntryByPath(db, 'specs/nonexistent.md');
    expect(entry).toBeNull();
  });

  test('returns empty runs array for spec with no runs', () => {
    const entryId = insertTestSpecEntry('specs/no-runs.md');
    const runs = getSpecRunsByEntry(db, entryId);
    expect(runs).toEqual([]);
  });

  test('handles worktree with unreadable spec path gracefully', () => {
    const id = insertTestWorktree({ spec_path: '/nonexistent/path/spec.md' });
    const wt = getWorktree(db, id)!;

    // In the TUI, readFile would fail, and the catch block sets specContent to null
    // Simulate: if file read fails, specContent is null
    let specContent: string[] | null = null;
    try {
      // This would throw in real TUI
      throw new Error('ENOENT');
    } catch {
      specContent = null;
    }

    expect(specContent).toBeNull();
  });
});

// ── Spec content preview ────────────────────────────────────

describe('TUI worktree detail: spec content preview', () => {
  test('shows first 20 lines of spec content', () => {
    const lines = Array.from({ length: 50 }, (_, i) => `Line ${i + 1}`);
    const content = lines.join('\n');

    const preview = content.split('\n').slice(0, 20);
    expect(preview.length).toBe(20);
    expect(preview[0]).toBe('Line 1');
    expect(preview[19]).toBe('Line 20');
  });

  test('shows all lines when spec is shorter than 20 lines', () => {
    const lines = ['# Short Spec', '', '## Outcome', '', 'A short spec.'];
    const content = lines.join('\n');

    const preview = content.split('\n').slice(0, 20);
    expect(preview.length).toBe(5);
  });

  test('reports remaining lines count when truncated', () => {
    const totalLines = 50;
    const displayedLines = 20;
    const remaining = totalLines - displayedLines;
    expect(remaining).toBe(30);
  });
});

// ── Run status display logic ────────────────────────────────

describe('TUI worktree detail: run status display', () => {
  test('passed/success runs get + icon with green color', () => {
    const statuses = ['passed', 'success'];
    for (const status of statuses) {
      const icon = (status === 'passed' || status === 'success') ? '+' : 'x';
      const color = (status === 'passed' || status === 'success') ? '#22c55e' : '#ef4444';
      expect(icon).toBe('+');
      expect(color).toBe('#22c55e');
    }
  });

  test('failed runs get x icon with red color', () => {
    const status = 'failed';
    const icon = (status === 'passed' || status === 'success') ? '+' : 'x';
    const color = (status === 'passed' || status === 'success') ? '#22c55e' : '#ef4444';
    expect(icon).toBe('x');
    expect(color).toBe('#ef4444');
  });

  test('cost formats as USD with 2 decimal places', () => {
    const cost = 3.5;
    const formatted = `$${cost.toFixed(2)}`;
    expect(formatted).toBe('$3.50');
  });

  test('null cost shows dash placeholder', () => {
    const cost: number | null = null;
    const formatted = cost != null ? `$${cost.toFixed(2)}` : '   -';
    expect(formatted).toBe('   -');
  });
});

// ── Live refresh via dbVersion ──────────────────────────────

describe('TUI worktree detail: live refresh on dbVersion change', () => {
  test('worktree data is refreshed when status changes in DB', () => {
    const id = insertTestWorktree({ spec_path: 'specs/refresh.md' });

    // Initial state
    expect(getWorktree(db, id)!.status).toBe('created');

    // Simulate status change (would trigger dbVersion increment)
    transitionWorktreeStatus(db, id, 'running');
    expect(getWorktree(db, id)!.status).toBe('running');

    transitionWorktreeStatus(db, id, 'complete');
    expect(getWorktree(db, id)!.status).toBe('complete');
  });

  test('run history updates when new runs are inserted', () => {
    const specPath = 'specs/live-runs.md';
    const entryId = insertTestSpecEntry(specPath);

    // Initially no runs
    expect(getSpecRunsByEntry(db, entryId).length).toBe(0);

    // Insert a run
    insertTestSpecRun(entryId, { status: 'passed', cost_usd: 1.0 });
    expect(getSpecRunsByEntry(db, entryId).length).toBe(1);

    // Insert another run
    insertTestSpecRun(entryId, { status: 'failed', cost_usd: 0.5 });
    expect(getSpecRunsByEntry(db, entryId).length).toBe(2);
  });
});

// ── Metadata display ────────────────────────────────────────

describe('TUI worktree detail: metadata sections', () => {
  test('displays work_group_id when present', () => {
    const id = insertTestWorktree({ work_group_id: 'wg-display-test' });
    const wt = getWorktree(db, id)!;
    expect(wt.work_group_id).toBe('wg-display-test');
  });

  test('omits work_group_id section when null', () => {
    const id = insertTestWorktree({});
    const wt = getWorktree(db, id)!;
    expect(wt.work_group_id).toBeNull();
  });

  test('displays error when present', () => {
    const id = insertTestWorktree({});
    transitionWorktreeStatus(db, id, 'failed', 'Setup failed: bun install timed out');
    const wt = getWorktree(db, id)!;
    expect(wt.error).toBe('Setup failed: bun install timed out');
  });

  test('displays multiple spec paths from spec_paths JSON', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/main.md',
      spec_paths: ['specs/main.md', 'specs/helper.md', 'specs/utils.md'],
      branch: `forge/${id}`,
      worktree_path: `/tmp/wt-${id}`,
      status: 'created',
    });

    const wt = getWorktree(db, id)!;
    const specPaths: string[] = JSON.parse(wt.spec_paths);
    expect(specPaths.length).toBe(3);
    expect(specPaths).toContain('specs/main.md');
    expect(specPaths).toContain('specs/helper.md');
  });
});
